SELECT number_of_students
FROM hei
WHERE hei_id = 1;

SELECT programme_name, degree_title
FROM programmes
WHERE degree_type = 'SCD integrated';

SELECT programme_name, enrollment_capacity
FROM programmes
ORDER BY programme_name;

SELECT COUNT(*)
FROM programmes
WHERE current_enrollment > 0;

SELECT programme_name, degree_title, programme_duration, mode_of_delivery, current_enrollment, programme_director
FROM programmes
WHERE programme_id = 1;

SELECT COUNT(accreditation_id) AS accreditation_count
FROM accreditation_details
WHERE programme_id = 1;

SELECT programme_name
FROM programmes
ORDER BY programme_name;

SELECT programme_name
FROM programmes
ORDER BY programme_name;
